let text = $json.TEXT || "";

// remover excesso de quebras de linha
text = text.replace(/\n{3,}/g, "\n\n");

// remover espaços duplicados
text = text.replace(/[ \t]+/g, " ");

// remover linhas vazias repetidas
text = text.replace(/(\n\s*)+\n/g, "\n\n");

// remover linhas com traços (assinaturas)
text = text.replace(/-{5,}.*/g, "");

// trim geral
text = text.trim();

return {
  json: {
    TEXT: text
  }
};

/**
 * PIPELINE PÓS LLM
 * Converte resposta do LLM em itens para Supabase
 */

// normalizador
const norm = (v) =>
  (v ?? "")
    .toString()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, "_")
    .replace(/[^a-z0-9_]/g, "");

// converter data
function convertDateToISO(dateStr) {

  if (!dateStr) return null;

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(dateStr)) {
    const [d,m,y] = dateStr.split("/");
    return `${y}-${m}-${d}`;
  }

  if (/^\d{2}\/\d{2}$/.test(dateStr)) {
    const [d,m] = dateStr.split("/");
    const y = new Date().getFullYear();
    return `${y}-${m}-${d}`;
  }

  return dateStr;
}


// ======================
// pegar resposta do LLM
// ======================

let raw = $json.text || "";

// remover ```json ```
raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error("Erro ao fazer parse do JSON do LLM");
}

const voos = parsed.voos || [];

const output = voos.map(voo => {

  const tipo_detectado = voo.tipo_detectado || "";

  const dataISO = convertDateToISO(voo.data);

  const dia_semana = voo.dia_semana || "";
  const hora = voo.hora || "";
  const aeronave = voo.aeronave || "";
  const destino = voo.destino || "";
  const passageiros = voo.passageiros || "";

  const ordem_dia =
    Number(voo.ordem_dia) && Number(voo.ordem_dia) > 0
      ? Number(voo.ordem_dia)
      : 1;

  // novo ID estável
  const flight_id = [
    norm(dataISO),
    norm(destino),
    ordem_dia
  ].join("_");

  const tabela_destino = `${tipo_detectado}_flights`;

  return {
    json: {
      tipo_detectado,
      tabela_destino,
      flight_id,
      data: dataISO,
      dia_semana,
      hora,
      aeronave,
      destino,
      passageiros,
      ordem_dia
    }
  };

});

return output;

