// voos vindos do email
const voosEmail = $items("Agrupar Voos Email")[0].json.voos_email || [];

// categoria
const tabelaEmail = voosEmail.length ? voosEmail[0].tabela_destino : null;

// data atual
const hoje = new Date().toISOString().slice(0,10);

// voos do banco (filtrados)
const voosDB = $items("Extrair Voos DB")
  .map(i => i.json)
  .filter(v => 
    v.tabela_destino === tabelaEmail &&
    v.data >= hoje
  );

// ids
const emailIds = voosEmail.map(v => v.flight_id);
const dbIds = voosDB.map(v => v.flight_id);

// novos
const voosNovos = voosEmail
  .filter(v => !dbIds.includes(v.flight_id))
  .map(v => ({ ...v, acao: "insert" }));

// existentes
const voosExistentes = voosEmail
  .filter(v => dbIds.includes(v.flight_id))
  .map(v => ({ ...v, acao: "update" }));

// removidos
const voosRemovidos = voosDB
  .filter(v => !emailIds.includes(v.flight_id))
  .map(v => ({ ...v, acao: "deactivate" }));

const resultado = [
  ...voosNovos,
  ...voosExistentes,
  ...voosRemovidos
];

return resultado.map(v => ({ json: v }));

